function Screenshot({ src, label, emoji = "📸" }: { src: string; label: string; emoji?: string }) {
  return (
    <div className="my-5 overflow-hidden rounded-[1rem] border border-slate-200 shadow-[0_4px_20px_rgba(15,28,56,0.08)]">
      <div className="flex items-center gap-2 border-b border-slate-100 bg-slate-50 px-4 py-2">
        <span className="text-base">{emoji}</span>
        <span className="text-xs font-bold uppercase tracking-[0.18em] text-slate-500">{label}</span>
      </div>
      <img src={src} alt={label} className="block w-full" />
    </div>
  );
}

function Instruction({
  num,
  color,
  bg,
  border,
  children,
}: {
  num: number;
  color: string;
  bg: string;
  border: string;
  children: React.ReactNode;
}) {
  return (
    <li className="flex items-start gap-4 border-b border-slate-100 py-3 text-sm text-slate-700 leading-7 last:border-b-0">
      <span
        className="mt-0.5 flex h-7 w-7 shrink-0 items-center justify-center rounded-full text-xs font-bold"
        style={{ background: bg, border: `1.5px solid ${border}`, color }}
      >
        {num}
      </span>
      <span>{children}</span>
    </li>
  );
}

function Code({ children }: { children: React.ReactNode }) {
  return (
    <code className="rounded-md border border-slate-200 bg-slate-100 px-1.5 py-0.5 font-mono text-[13px] font-bold text-[#1B2D5B]">
      {children}
    </code>
  );
}

function ExternalLink({ href, children }: { href: string; children: React.ReactNode }) {
  return (
    <a
      href={href}
      target="_blank"
      rel="noreferrer"
      className="font-bold text-[#2D8EFF] underline underline-offset-2 hover:text-[#1B2D5B] transition-colors"
    >
      {children}
    </a>
  );
}

